#include <iostream>

using namespace std;

struct TreeNode
{
    int data;
    TreeNode *left;
    TreeNode *right;
};

int countNodes(TreeNode *node)
{
    if (node == nullptr) // BASE CASE
    {
        return 0;
    }
    return 1 + countNodes(node->left) + countNodes(node->right); // RECURSIVE CASE
}

int main()
{
    TreeNode *root = new TreeNode{1, nullptr, nullptr};
    root->left = new TreeNode{2, nullptr, nullptr};
    root->right = new TreeNode{3, nullptr, nullptr};
    root->left->left = new TreeNode{4, nullptr, nullptr};
    root->left->right = new TreeNode{5, nullptr, nullptr};

    cout << countNodes(root) << endl;

    return 0;
}

